//! Auto-generated by the spec-word-compliance workflow for area
//! "MCE: AlternateContent/Choice/Fallback resolution +
//! Ignorable/ProcessContent/MustUnderstand" (ISO/IEC 29500-3, Markup
//! Compatibility & Extensibility).
//!
//! Each `#[test]` encodes a Word *consumption* semantic for MCE preprocessing:
//! how a conforming MCE consumer (Microsoft Word, the reference implementation)
//! resolves `mc:AlternateContent` Choice/Fallback selection, honours
//! `mc:Ignorable`/`mc:ProcessContent`, and scopes `mc:MustUnderstand`.
//!
//! A FAILING assertion here is NOT a test bug to paper over: it encodes a real
//! Word-compliance gap in stemma's MCE handling. The expected values come
//! straight from the §refs cited in each assert message. Do not weaken an
//! assertion to make it pass — investigate the divergence.
//!
//! Methodology note (consumption vs. save): these tests assert on the READ side
//! (`read_accepted()`/`read_rejected()` text) and on opens-clean, never on the
//! verbatim re-serialized XML. stemma round-trips untouched content
//! byte-for-byte, so re-serialized XML reflects preservation, not Word's MCE
//! resolution. MCE resolution is a consumption-time transform, so the read view
//! is the correct surface to assert against.

use std::io::{Read, Write};

use stemma::ExportOptions;
use stemma::api::Document;

// ─── Prelude: minimal .docx plumbing ────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document …><w:body>…</w:body></w:document>`. Only the `w` namespace is
/// declared on `<w:document>`; every spec declares the MCE / shape / extension
/// namespaces it needs inline on its own elements (as in real Word output).
///
/// `extra_parts` are `(zip path, xml content)` pairs (e.g.
/// `("word/styles.xml", …)`) that also get a `[Content_Types].xml` Override and
/// a `document.xml.rels` entry. None of the current specs need extra parts; the
/// parameter is kept per the workflow prelude contract.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    let mut content_types = String::from(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (path, _) in extra_parts {
        let content_type = match *path {
            "word/styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "word/numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            other => panic!("make_docx: no content type mapped for extra part {other}"),
        };
        content_types.push_str(&format!(
            r#"<Override PartName="/{path}" ContentType="{content_type}"/>"#
        ));
    }
    content_types.push_str("</Types>");

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    let mut doc_rels = String::from(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">"#,
    );
    for (rid, (path, _)) in (100..).zip(extra_parts.iter()) {
        let rel_type = match *path {
            "word/styles.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles"
            }
            "word/numbering.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering"
            }
            other => panic!("make_docx: no relationship type mapped for extra part {other}"),
        };
        let target = path.trim_start_matches("word/");
        doc_rels.push_str(&format!(
            r#"<Relationship Id="rId{rid}" Type="{rel_type}" Target="{target}"/>"#
        ));
    }
    doc_rels.push_str("</Relationships>");

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: zip::write::FileOptions = zip::write::FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (path, content) in extra_parts {
            zip.start_file(*path, opts).unwrap();
            zip.write_all(content.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
#[allow(dead_code)]
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive =
        zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open produced docx as zip");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present in produced docx");
    let mut xml = String::new();
    file.read_to_string(&mut xml).expect("read document.xml");
    xml
}

/// Parse -> serialize (default ExportOptions) -> word/document.xml.
/// NOTE: stemma round-trips untouched content byte-verbatim, so this reflects
/// the verbatim-preservation contract, not Word's save normalization. None of
/// the current specs use xml* expectations; kept per the workflow prelude
/// contract.
#[allow(dead_code)]
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("Document::parse for reserialize");
    let out = doc
        .serialize(&ExportOptions::default())
        .expect("serialize with default ExportOptions");
    document_xml_of(&out)
}

/// Accept-all reading of the document text, trimmed. A parse refusal here is
/// itself a finding when Word opens the same bytes clean — the panic message
/// carries the rule context.
fn accept_text(bytes: &[u8], rule_context: &str) -> String {
    let doc = Document::parse(bytes).unwrap_or_else(|e| {
        panic!("Document::parse refused a document Word opens — {rule_context}: {e:?}")
    });
    doc.read_accepted()
        .unwrap_or_else(|e| panic!("read_accepted failed — {rule_context}: {e:?}"))
        .to_text()
        .trim()
        .to_string()
}

/// Reject-all reading of the document text, trimmed.
fn reject_text(bytes: &[u8], rule_context: &str) -> String {
    let doc = Document::parse(bytes).unwrap_or_else(|e| {
        panic!("Document::parse refused a document Word opens — {rule_context}: {e:?}")
    });
    doc.read_rejected()
        .unwrap_or_else(|e| panic!("read_rejected failed — {rule_context}: {e:?}"))
        .to_text()
        .trim()
        .to_string()
}

/// Assert `stemma::api::validate` reports no errors (opens-clean proxy).
fn assert_opens_clean(bytes: &[u8], rule_context: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok,
        "expected document to validate clean (Word opens it without repair) — {rule_context}; issues: {:?}",
        report.issues
    );
}

