#[test]
fn choice_requires_all_namespaces_understood_else_fallback() {
    let rule = "ISO/IEC 29500-3 §7.6/§9.3/§9.4: Requires is a whitespace-delimited list; selection requires EVERY listed namespace understood (conjunction). wps is understood, unk is not, so the Choice is skipped and the Fallback is selected.";
    let body = r#"<w:p><mc:AlternateContent xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006" xmlns:wps="http://schemas.microsoft.com/office/word/2010/wordprocessingShape" xmlns:unk="http://example.com/unknown-future-extension"><mc:Choice Requires="wps unk"><w:r><w:t>CHOICE_BRANCH</w:t></w:r></mc:Choice><mc:Fallback><w:r><w:t>FALLBACK_BRANCH</w:t></w:r></mc:Fallback></mc:AlternateContent></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b, rule),
        "FALLBACK_BRANCH",
        "{rule} — accept-all text must be the Fallback branch."
    );
    assert_eq!(
        reject_text(&b, rule),
        "FALLBACK_BRANCH",
        "{rule} — no tracked changes, so reject reading equals accept reading."
    );
    assert_opens_clean(
        &b,
        "ISO/IEC 29500-3 §7.6: one Choice followed by one Fallback is valid; an unsatisfiable Choice is skipped, not an error.",
    );
}

#[test]
fn choice_requires_multiple_all_understood_selects_choice() {
    let rule = "ISO/IEC 29500-3 §9.3/§9.4: both wps and wpg are in Word's MCE configuration, so the conjunctive Requires=\"wps wpg\" test passes and the Choice is selected over the Fallback.";
    let body = r#"<w:p><mc:AlternateContent xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006" xmlns:wps="http://schemas.microsoft.com/office/word/2010/wordprocessingShape" xmlns:wpg="http://schemas.microsoft.com/office/word/2010/wordprocessingGroup"><mc:Choice Requires="wps wpg"><w:r><w:t>BOTH_UNDERSTOOD</w:t></w:r></mc:Choice><mc:Fallback><w:r><w:t>FALLBACK_BRANCH</w:t></w:r></mc:Fallback></mc:AlternateContent></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b, rule),
        "BOTH_UNDERSTOOD",
        "{rule} — accept-all text must be the selected Choice branch."
    );
    assert_eq!(
        reject_text(&b, rule),
        "BOTH_UNDERSTOOD",
        "{rule} — no tracked changes, so reject reading equals accept reading."
    );
    assert_opens_clean(
        &b,
        "ISO/IEC 29500-3 §7.6: one Choice followed by one Fallback is valid; a satisfiable Choice is selected normally.",
    );
}

#[test]
fn nested_alternatecontent_inner_choice_discarded_when_parent_choice_unselected() {
    let rule = "ISO/IEC 29500-3 §9.3/§9.4: the outer Choice requires unknown ns unk so it is not selected; a selected inner Choice's content is DISCARDED when an ancestor Choice is not selected, so the outer Fallback wins.";
    let body = r#"<w:p><mc:AlternateContent xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006" xmlns:unk="http://example.com/unknown-future-extension" xmlns:wps="http://schemas.microsoft.com/office/word/2010/wordprocessingShape"><mc:Choice Requires="unk"><mc:AlternateContent><mc:Choice Requires="wps"><w:r><w:t>INNER_CURRENT</w:t></w:r></mc:Choice><mc:Fallback><w:r><w:t>INNER_FALLBACK</w:t></w:r></mc:Fallback></mc:AlternateContent></mc:Choice><mc:Fallback><w:r><w:t>OUTER_FALLBACK</w:t></w:r></mc:Fallback></mc:AlternateContent></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b, rule),
        "OUTER_FALLBACK",
        "{rule} — accept-all text must be OUTER_FALLBACK, never INNER_CURRENT."
    );
    assert_eq!(
        reject_text(&b, rule),
        "OUTER_FALLBACK",
        "{rule} — no tracked changes, so reject reading equals accept reading."
    );
    assert_opens_clean(
        &b,
        "ISO/IEC 29500-3 §7.5: nested AlternateContent (an AC as the sole content of an outer Choice) is valid.",
    );
}

#[ignore = "open question: Document::parse refuses a nested AlternateContent surfacing inside a selected outer Choice (RuntimeError InvalidDocx: unknown paragraph-level element: AlternateContent); §9.4 Step-3 must recurse into the nested AC and resolve its inner Choice to INNER_CURRENT, but stemma does not handle a nested AC inside a selected Choice"]
#[test]
fn nested_alternatecontent_inner_choice_surfaces_when_parent_choice_selected() {
    let rule = "ISO/IEC 29500-3 §9.4: the outer Choice (Requires wps) is selected, so Step 3 recurses into its inner AlternateContent where the inner Choice (Requires wpg) is also selected — INNER_CURRENT surfaces.";
    let body = r#"<w:p><mc:AlternateContent xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006" xmlns:wps="http://schemas.microsoft.com/office/word/2010/wordprocessingShape" xmlns:wpg="http://schemas.microsoft.com/office/word/2010/wordprocessingGroup"><mc:Choice Requires="wps"><mc:AlternateContent><mc:Choice Requires="wpg"><w:r><w:t>INNER_CURRENT</w:t></w:r></mc:Choice><mc:Fallback><w:r><w:t>INNER_FALLBACK</w:t></w:r></mc:Fallback></mc:AlternateContent></mc:Choice><mc:Fallback><w:r><w:t>OUTER_FALLBACK</w:t></w:r></mc:Fallback></mc:AlternateContent></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b, rule),
        "INNER_CURRENT",
        "{rule} — accept-all text must be INNER_CURRENT, never INNER_FALLBACK or OUTER_FALLBACK."
    );
    assert_eq!(
        reject_text(&b, rule),
        "INNER_CURRENT",
        "{rule} — no tracked changes, so reject reading equals accept reading."
    );
    assert_opens_clean(
        &b,
        "ISO/IEC 29500-3 §7.5: nested AlternateContent with all-understood Requires is valid and resolves without repair.",
    );
}

#[test]
fn selected_choice_content_discarded_when_ancestor_element_ignored() {
    let rule = "ISO/IEC 29500-3 §9.2/§9.4: ext:wrap is declared-ignorable, unknown ns, no ProcessContent match, so it is marked ignored and removed WITH all contents — including the nested AlternateContent whose inner Choice would otherwise be selected.";
    let body = r#"<w:p><w:r><w:t>BEFORE</w:t></w:r><ext:wrap xmlns:ext="http://example.com/future-extension" xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006" xmlns:wps="http://schemas.microsoft.com/office/word/2010/wordprocessingShape" mc:Ignorable="ext"><mc:AlternateContent><mc:Choice Requires="wps"><w:r><w:t>INNER_CHOICE</w:t></w:r></mc:Choice><mc:Fallback><w:r><w:t>INNER_FALLBACK</w:t></w:r></mc:Fallback></mc:AlternateContent></ext:wrap><w:r><w:t>AFTER</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b, rule),
        "BEFOREAFTER",
        "{rule} — the ignored subtree contributes no text; only BEFORE and AFTER read."
    );
    assert_eq!(
        reject_text(&b, rule),
        "BEFOREAFTER",
        "{rule} — no tracked changes, so reject reading equals accept reading."
    );
    assert_opens_clean(
        &b,
        "ISO/IEC 29500-3 §7.5/§9.2: an ignorable, not-understood element with a declared mc:Ignorable namespace is removed during MCE preprocessing, not an error.",
    );
}

#[test]
fn choice_requires_conjunction_one_unknown_namespace_skips_choice() {
    let rule = "ISO/IEC 29500-3 §9.3/§7.6: Requires=\"w zz\" is NOT selected because zz is unknown even though w is understood (conjunction); with no other Choice the Fallback is selected.";
    let body = r#"<w:p xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006" xmlns:zz="urn:unknown:zz"><w:r><w:t xml:space="preserve">A </w:t></w:r><mc:AlternateContent><mc:Choice Requires="w zz"><w:r><w:t>CHOICE</w:t></w:r></mc:Choice><mc:Fallback><w:r><w:t>FALLBACK</w:t></w:r></mc:Fallback></mc:AlternateContent><w:r><w:t xml:space="preserve"> Z</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b, rule),
        "A FALLBACK Z",
        "{rule} — FALLBACK surfaces between the surrounding runs."
    );
    assert_eq!(
        reject_text(&b, rule),
        "A FALLBACK Z",
        "{rule} — no tracked changes, so reject-all equals accept-all."
    );
    assert_opens_clean(
        &b,
        "ISO/IEC 29500-3 §7.6: a well-formed AlternateContent with a Fallback is valid.",
    );
}

#[test]
fn choice_requires_multiple_ns_all_must_be_understood() {
    let rule = "ISO/IEC 29500-3 §9.3/§7.6/§7.7: Requires=\"w zz\" and zz is not in the configuration, so NOT every required namespace is understood; the Choice is skipped and the Fallback is selected.";
    let body = r#"<w:p><w:r><w:t>A</w:t></w:r><mc:AlternateContent xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006" xmlns:zz="http://example.com/totally-unknown-ns"><mc:Choice Requires="w zz"><w:r><w:t>CHOICE</w:t></w:r></mc:Choice><mc:Fallback><w:r><w:t>FALLBACK</w:t></w:r></mc:Fallback></mc:AlternateContent><w:r><w:t>B</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b, rule),
        "AFALLBACKB",
        "{rule} — yielding AFALLBACKB."
    );
    assert_eq!(
        reject_text(&b, rule),
        "AFALLBACKB",
        "{rule} — no tracked changes, so reject-all reads identically to accept-all."
    );
    assert_opens_clean(
        &b,
        "ISO/IEC 29500-3 §9.3: a well-formed AlternateContent with a satisfiable Fallback opens without repair; skipping an unsatisfiable Choice is normal MCE processing.",
    );
}

