#[test]
fn ignorable_does_not_drop_understood_namespace_sibling() {
    let rule = "ISO/IEC 29500-3 §9.2/§7.2: the WML runs are in the configuration so they are never ignored despite mc:Ignorable=\"zz\"; zz:foo IS declared-ignorable, not-understood, no ProcessContent match, so only it is dropped.";
    let body = r#"<w:p mc:Ignorable="zz" xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006" xmlns:zz="http://example.com/unknown"><w:r><w:t>KEEP</w:t></w:r><zz:foo><w:r><w:t>GONE</w:t></w:r></zz:foo><w:r><w:t>ME</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b, rule),
        "KEEPME",
        "{rule} — leaving KEEPME (GONE is dropped with the ignorable element)."
    );
    assert_eq!(
        reject_text(&b, rule),
        "KEEPME",
        "{rule} — no tracked changes, so reject-all equals accept-all."
    );
    assert_opens_clean(
        &b,
        "ISO/IEC 29500-3 §7.2/§9.2: a paragraph with a declared-ignorable foreign child and a valid mc:Ignorable opens without repair.",
    );
}

