#[ignore = "open question: Document::parse over-refuses on mc:MustUnderstand on a NON-selected Choice (RuntimeError InvalidDocx: mc:MustUnderstand requires namespace ... refusing); §9.4 examines MustUnderstand only on the AC element and on the SELECTED Choice/Fallback — the first Choice (Requires=w) is selected so the later Choice's mc:MustUnderstand=q is inert and Word opens clean, but stemma's Step-1 walks every subtree element and over-refuses"]
#[test]
fn mce_mustunderstand_on_nonselected_choice_is_not_examined() {
    let rule = "ISO/IEC 29500-3 §9.4/§7.4: MustUnderstand is examined ONLY on the AC and on the SELECTED Choice/Fallback; the first Choice (Requires=\"w\") is selected, so the later non-selected Choice's mc:MustUnderstand=\"q\" is inert and must not cause refusal.";
    let body = r#"<w:p><w:r><w:t>before </w:t></w:r><mc:AlternateContent xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006"><mc:Choice Requires="w"><w:r><w:t>chosen</w:t></w:r></mc:Choice><mc:Choice Requires="q" mc:MustUnderstand="q" xmlns:q="http://example.com/quux-unknown"><w:r><w:t>never</w:t></w:r></mc:Choice></mc:AlternateContent><w:r><w:t> after</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ISO/IEC 29500-3 §9.4: the non-selected Choice's mc:MustUnderstand=\"q\" is inert — the document must open without a mismatch.",
    );
    assert_eq!(
        accept_text(&b, rule),
        "before chosen after",
        "{rule} — read is the surrounding runs plus the chosen branch text."
    );
    assert_eq!(
        reject_text(&b, rule),
        "before chosen after",
        "{rule} — no tracked changes, so reject-all equals accept-all."
    );
}
